#include <vector>
#include <unordered_map>
#include <unordered_set>
#include <algorithm>

using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> minNode;
public:
    UnionFind(long long size) {
        parent.resize(size + 1);
        minNode.resize(size + 1);
        for (long long i = 1; i <= size; ++i) {
            parent[i] = i;
            minNode[i] = i;
        }
    }

    long long find(long long u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    void unionNodes(long long u, long long v) {
        long long rootU = find(u);
        long long rootV = find(v);
        if (rootU != rootV) {
            if (rootU < rootV) {
                parent[rootV] = rootU;
                minNode[rootU] = min(minNode[rootU], minNode[rootV]);
            } else {
                parent[rootU] = rootV;
                minNode[rootV] = min(minNode[rootV], minNode[rootU]);
            }
        }
    }

    long long getMinNode(long long u) {
        return minNode[find(u)];
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    UnionFind uf(c);
    for (const auto& conn : connections) {
        uf.unionNodes(conn[0], conn[1]);
    }

    vector<bool> online(c + 1, true);
    unordered_map<long long, unordered_set<long long>> componentNodes;
    for (long long i = 1; i <= c; ++i) {
        long long root = uf.find(i);
        componentNodes[root].insert(i);
    }

    unordered_map<long long, long long> componentMinOnline;
    for (const auto& entry : componentNodes) {
        long long root = entry.first;
        componentMinOnline[root] = *min_element(entry.second.begin(), entry.second.end());
    }

    vector<long long> result;
    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = uf.find(x);
                if (componentMinOnline.find(root) == componentMinOnline.end()) {
                    result.push_back(-1);
                } else {
                    result.push_back(componentMinOnline[root]);
                }
            }
        } else if (type == 2) {
            online[x] = false;
            long long root = uf.find(x);
            if (componentMinOnline.find(root) != componentMinOnline.end() && componentMinOnline[root] == x) {
                long long newMin = -1;
                for (long long node : componentNodes[root]) {
                    if (online[node]) {
                        if (newMin == -1 || node < newMin) {
                            newMin = node;
                        }
                    }
                }
                componentMinOnline[root] = newMin;
            }
        }
    }
    return result;
}
